// pages/Progress.jsx — Topic completion tracker + AI suggestions
import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import { TOPICS } from "../data/topicsData";
import { getCompletedTopics, getQuizScores, clearProgress } from "../utils/progress";

const API_BASE = process.env.REACT_APP_API_URL || "http://localhost:5000";

// ── Helpers ───────────────────────────────────────────────────────────────────
function getTopicScore(quizScores, topicName) {
  const matches = quizScores.filter(s =>
    s.topic.toLowerCase().includes(topicName.toLowerCase()) ||
    topicName.toLowerCase().includes(s.topic.toLowerCase())
  );
  if (matches.length === 0) return null;
  const avg = Math.round(matches.reduce((sum, s) => sum + (s.score / s.total) * 100, 0) / matches.length);
  return { avg, attempts: matches.length };
}

function scoreColor(pct) {
  if (pct >= 80) return "#22c55e";
  if (pct >= 60) return "#f59e0b";
  return "#f87171";
}

// ── AI Suggestions Panel ──────────────────────────────────────────────────────
function AISuggestions({ completedTopics, quizScores, allTopics }) {
  const [suggestion, setSuggestion] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [fetched, setFetched] = useState(false);

  // Static fallback based on local data
  const staticSuggestion = () => {
    const completedNames = allTopics.filter(t => completedTopics.includes(t.slug)).map(t => t.name);
    const weakTopics = quizScores.filter(s => (s.score / s.total) * 100 < 60).map(s => s.topic);
    const notStarted = allTopics.filter(t => !completedTopics.includes(t.slug)).map(t => t.name);
    return {
      summary: completedNames.length === 0
        ? "You're just getting started! Begin with foundational topics to build your confidence."
        : `You've completed ${completedNames.length} topics so far. Keep up the momentum!`,
      nextTopics: notStarted.slice(0, 3),
      nextTopicsReason: "These are the next logical topics in your learning path.",
      weakAreas: weakTopics.slice(0, 2),
      weakAreasAdvice: weakTopics.length > 0
        ? "Revisit the learn page for these topics and attempt practice before retaking the quiz."
        : "No weak areas detected yet — great job!",
      encouragement: quizScores.length === 0
        ? "Take your first quiz to unlock personalized AI feedback! 🎯"
        : "Every quiz makes you sharper. Keep going! 💪",
    };
  };

  const fetchSuggestions = async () => {
    setLoading(true);
    setError("");
    try {
      const res = await fetch(`${API_BASE}/api/suggestions`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ completedTopics, quizScores, allTopics }),
      });
      const json = await res.json();
      if (!res.ok || !json.success) throw new Error(json.details || json.error || "Server error");
      setSuggestion(json.data);
      setFetched(true);
    } catch (err) {
      setError("Could not load AI suggestions: " + err.message);
    }
    setLoading(false);
  };

  const data = suggestion || staticSuggestion();

  return (
    <section style={{ marginBottom: 24, animation: "fadeUp 0.5s 0.15s ease both" }}>
      {/* Header */}
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:14 }}>
        <div style={{ display:"flex", alignItems:"center", gap:8 }}>
          <div style={{ width:32, height:32, borderRadius:10, background:"linear-gradient(135deg,#6366f1,#8b5cf6)", display:"flex", alignItems:"center", justifyContent:"center", fontSize:16 }}>🤖</div>
          <div>
            <p style={{ margin:0, fontSize:"0.82rem", fontWeight:700, color:"#e2e8f0" }}>AI Study Coach</p>
            <p style={{ margin:0, fontSize:"0.68rem", color:"#475569" }}>{fetched ? "Personalized AI analysis" : "Based on your progress"}</p>
          </div>
        </div>
        <button onClick={fetchSuggestions} disabled={loading} style={{
          padding:"7px 14px", borderRadius:10, border:"1px solid rgba(99,102,241,0.35)",
          background:"rgba(99,102,241,0.1)", color:"#a5b4fc",
          fontSize:"0.72rem", fontWeight:600, cursor: loading ? "not-allowed" : "pointer",
          opacity: loading ? 0.6 : 1, transition:"all 0.2s"
        }}>
          {loading ? "Thinking…" : fetched ? "🔄 Refresh" : "✨ Get AI Advice"}
        </button>
      </div>

      {error && (
        <div style={{ padding:"10px 14px", borderRadius:10, background:"rgba(239,68,68,0.08)", border:"1px solid rgba(239,68,68,0.2)", marginBottom:12 }}>
          <p style={{ margin:0, fontSize:"0.75rem", color:"#f87171" }}>{error}</p>
        </div>
      )}

      {loading && (
        <div style={{ padding:"28px", textAlign:"center", borderRadius:16, background:"rgba(99,102,241,0.05)", border:"1px solid rgba(99,102,241,0.12)" }}>
          <div style={{ fontSize:"1.8rem", marginBottom:8, animation:"pulse 1.2s ease-in-out infinite" }}>🧠</div>
          <p style={{ margin:0, fontSize:"0.8rem", color:"#6366f1" }}>Analyzing your progress…</p>
        </div>
      )}

      {!loading && data && (
        <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
          {/* Summary */}
          <div style={{ padding:"14px 16px", borderRadius:14, background:"rgba(99,102,241,0.07)", border:"1px solid rgba(99,102,241,0.15)" }}>
            <p style={{ margin:"0 0 4px", fontSize:"0.7rem", color:"#818cf8", fontWeight:700, textTransform:"uppercase", letterSpacing:"0.07em" }}>📊 Assessment</p>
            <p style={{ margin:0, fontSize:"0.83rem", color:"#c7d2fe", lineHeight:1.6 }}>{data.summary}</p>
          </div>

          {/* Next topics */}
          {data.nextTopics?.length > 0 && (
            <div style={{ padding:"14px 16px", borderRadius:14, background:"rgba(56,189,248,0.07)", border:"1px solid rgba(56,189,248,0.15)" }}>
              <p style={{ margin:"0 0 8px", fontSize:"0.7rem", color:"#38bdf8", fontWeight:700, textTransform:"uppercase", letterSpacing:"0.07em" }}>🎯 Study Next</p>
              <div style={{ display:"flex", flexWrap:"wrap", gap:6, marginBottom:8 }}>
                {data.nextTopics.map(t => (
                  <span key={t} style={{ padding:"4px 10px", borderRadius:8, background:"rgba(56,189,248,0.12)", border:"1px solid rgba(56,189,248,0.2)", fontSize:"0.75rem", color:"#7dd3fc", fontWeight:500 }}>{t}</span>
                ))}
              </div>
              <p style={{ margin:0, fontSize:"0.75rem", color:"#64748b", lineHeight:1.5 }}>{data.nextTopicsReason}</p>
            </div>
          )}

          {/* Weak areas */}
          {data.weakAreas?.length > 0 && (
            <div style={{ padding:"14px 16px", borderRadius:14, background:"rgba(245,158,11,0.07)", border:"1px solid rgba(245,158,11,0.15)" }}>
              <p style={{ margin:"0 0 8px", fontSize:"0.7rem", color:"#f59e0b", fontWeight:700, textTransform:"uppercase", letterSpacing:"0.07em" }}>⚠️ Needs Work</p>
              <div style={{ display:"flex", flexWrap:"wrap", gap:6, marginBottom:8 }}>
                {data.weakAreas.map(t => (
                  <span key={t} style={{ padding:"4px 10px", borderRadius:8, background:"rgba(245,158,11,0.12)", border:"1px solid rgba(245,158,11,0.2)", fontSize:"0.75rem", color:"#fcd34d", fontWeight:500 }}>{t}</span>
                ))}
              </div>
              <p style={{ margin:0, fontSize:"0.75rem", color:"#64748b", lineHeight:1.5 }}>{data.weakAreasAdvice}</p>
            </div>
          )}

          {/* Encouragement */}
          <div style={{ padding:"12px 16px", borderRadius:14, background:"rgba(34,197,94,0.06)", border:"1px solid rgba(34,197,94,0.15)", display:"flex", alignItems:"center", gap:10 }}>
            <span style={{ fontSize:"1.2rem" }}>💬</span>
            <p style={{ margin:0, fontSize:"0.8rem", color:"#86efac", lineHeight:1.5, fontStyle:"italic" }}>{data.encouragement}</p>
          </div>
        </div>
      )}
    </section>
  );
}

// ── Topic Row ─────────────────────────────────────────────────────────────────
function TopicRow({ topic, isCompleted, quizData, onToggle }) {
  return (
    <div style={{ display:"flex", alignItems:"center", gap:12, padding:"11px 16px", borderBottom:"1px solid rgba(255,255,255,0.04)" }}>
      <button onClick={() => onToggle(topic.slug)} title={isCompleted ? "Mark incomplete" : "Mark complete"} style={{
        flexShrink:0, width:22, height:22, borderRadius:7,
        border:`2px solid ${isCompleted ? "#22c55e" : "rgba(255,255,255,0.12)"}`,
        background: isCompleted ? "rgba(34,197,94,0.15)" : "transparent",
        display:"flex", alignItems:"center", justifyContent:"center",
        cursor:"pointer", transition:"all 0.2s", fontSize:"0.7rem", color:"#22c55e"
      }}>
        {isCompleted ? "✓" : ""}
      </button>

      <Link to={`/topic/${topic.slug}`} style={{ flex:1, textDecoration:"none" }}>
        <span style={{ fontSize:"0.85rem", fontWeight:500, color: isCompleted ? "#e2e8f0" : "#64748b" }}>
          {topic.name}
        </span>
      </Link>

      {quizData ? (
        <div style={{ textAlign:"right", flexShrink:0 }}>
          <span style={{
            fontSize:"0.72rem", fontWeight:700, fontFamily:"monospace",
            color:scoreColor(quizData.avg), padding:"3px 8px", borderRadius:7,
            background:`${scoreColor(quizData.avg)}15`, border:`1px solid ${scoreColor(quizData.avg)}30`
          }}>{quizData.avg}%</span>
          <p style={{ margin:"2px 0 0", fontSize:"0.62rem", color:"#475569", textAlign:"right" }}>{quizData.attempts}x</p>
        </div>
      ) : (
        <Link to="/quiz" style={{ textDecoration:"none" }}>
          <span style={{ fontSize:"0.68rem", color:"#334155", padding:"3px 8px", borderRadius:7, border:"1px dashed rgba(255,255,255,0.07)", whiteSpace:"nowrap" }}>Quiz →</span>
        </Link>
      )}
    </div>
  );
}

// ── Recent Quizzes with expandable answer explanations ────────────────────────
function RecentQuizzes({ quizScores }) {
  const [openIdx, setOpenIdx] = useState(null);
  const [openQIdx, setOpenQIdx] = useState(null);
  const recent = [...quizScores].reverse().slice(0, 5);

  return (
    <section style={{ marginTop:20, animation:"fadeUp 0.4s 0.25s ease both" }}>
      <p style={{ margin:"0 0 10px", fontSize:"0.72rem", color:"#475569", fontWeight:700, textTransform:"uppercase", letterSpacing:"0.07em" }}>
        Recent Quizzes
      </p>
      <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
        {recent.map((s, i) => {
          const pct = Math.round((s.score / s.total) * 100);
          const isOpen = openIdx === i;
          return (
            <div key={i} style={{ borderRadius:14, border:"1px solid rgba(255,255,255,0.06)", background:"rgba(255,255,255,0.02)", overflow:"hidden" }}>
              {/* Quiz header row */}
              <button onClick={() => { setOpenIdx(isOpen ? null : i); setOpenQIdx(null); }} style={{
                width:"100%", display:"flex", alignItems:"center", justifyContent:"space-between",
                padding:"12px 16px", background:"transparent", border:"none", cursor:"pointer", textAlign:"left",
              }}>
                <div>
                  <p style={{ margin:0, fontSize:"0.83rem", color:"#cbd5e1", fontWeight:600 }}>{s.topic}</p>
                  <p style={{ margin:0, fontSize:"0.68rem", color:"#475569", marginTop:2 }}>
                    {new Date(s.date).toLocaleDateString("en-IN", { day:"numeric", month:"short", year:"numeric" })}
                    {s.breakdown?.length > 0 && <span style={{ marginLeft:6, color:"#334155" }}>· click to review</span>}
                  </p>
                </div>
                <div style={{ display:"flex", alignItems:"center", gap:8 }}>
                  <span style={{ fontSize:"0.78rem", fontWeight:700, fontFamily:"monospace", color:scoreColor(pct), padding:"3px 10px", borderRadius:8, background:`${scoreColor(pct)}15`, border:`1px solid ${scoreColor(pct)}30` }}>
                    {s.score}/{s.total} · {pct}%
                  </span>
                  {s.breakdown?.length > 0 && (
                    <span style={{ fontSize:"0.65rem", color:"#475569" }}>{isOpen ? "▲" : "▼"}</span>
                  )}
                </div>
              </button>

              {/* Expandable breakdown with explanations */}
              {isOpen && s.breakdown?.length > 0 && (
                <div style={{ borderTop:"1px solid rgba(255,255,255,0.05)", padding:"10px 12px", display:"flex", flexDirection:"column", gap:6 }}>
                  {s.breakdown.map((b, qi) => {
                    const isQOpen = openQIdx === `${i}-${qi}`;
                    return (
                      <div key={qi} style={{ borderRadius:10, border:`1px solid ${b.isRight ? "rgba(34,197,94,0.12)" : "rgba(239,68,68,0.12)"}`, overflow:"hidden" }}>
                        <button onClick={() => setOpenQIdx(isQOpen ? null : `${i}-${qi}`)} style={{
                          width:"100%", display:"flex", alignItems:"flex-start", gap:10, padding:"10px 12px",
                          background:"transparent", border:"none", cursor:"pointer", textAlign:"left",
                        }}>
                          <span style={{ flexShrink:0, width:20, height:20, borderRadius:6, display:"flex", alignItems:"center", justifyContent:"center", fontSize:"0.65rem", fontWeight:700, background:b.isRight?"rgba(34,197,94,0.15)":"rgba(239,68,68,0.15)", color:b.isRight?"#22c55e":"#ef4444", marginTop:1 }}>
                            {b.isRight ? "✓" : "✗"}
                          </span>
                          <div style={{ flex:1 }}>
                            <p style={{ margin:0, fontSize:"0.78rem", color:"#cbd5e1", lineHeight:1.4 }}>{b.question}</p>
                            {!b.isRight && (
                              <p style={{ margin:"3px 0 0", fontSize:"0.68rem", color:"#64748b" }}>
                                You: <span style={{ color:"#f87171" }}>{b.chosen || "Timed out"}</span>
                                {" · "}Answer: <span style={{ color:"#22c55e" }}>{b.correct}</span>
                              </p>
                            )}
                          </div>
                          {b.explanation && (
                            <span style={{ fontSize:"0.6rem", color:"#334155", flexShrink:0, marginTop:2 }}>
                              {isQOpen ? "▲" : "▼"}
                            </span>
                          )}
                        </button>

                        {/* Explanation */}
                        {isQOpen && b.explanation && (
                          <div style={{ margin:"0 12px 10px", padding:"10px 12px", borderRadius:8, background:"rgba(56,189,248,0.07)", border:"1px solid rgba(56,189,248,0.15)" }}>
                            <p style={{ margin:"0 0 3px", fontSize:"0.65rem", color:"#7dd3fc", fontWeight:700, textTransform:"uppercase", letterSpacing:"0.06em" }}>💡 Explanation</p>
                            <p style={{ margin:0, fontSize:"0.77rem", color:"#bae6fd", lineHeight:1.6 }}>{b.explanation}</p>
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </section>
  );
}

// ── Main Progress Page ────────────────────────────────────────────────────────
export default function Progress() {
  const [completed, setCompleted] = useState(getCompletedTopics());
  const [quizScores, setQuizScores] = useState(getQuizScores());
  const [filter, setFilter] = useState("all");

  useEffect(() => {
    const refresh = () => {
      setCompleted(getCompletedTopics());
      setQuizScores(getQuizScores());
    };
    window.addEventListener("focus", refresh);
    return () => window.removeEventListener("focus", refresh);
  }, []);

  const handleToggle = (slug) => {
    const current = getCompletedTopics();
    const updated = current.includes(slug) ? current.filter(s => s !== slug) : [...current, slug];
    localStorage.setItem("aptiprep_completed", JSON.stringify(updated));
    setCompleted(updated);
  };

  const handleClear = () => {
    if (window.confirm("Clear all progress data? This cannot be undone.")) {
      clearProgress();
      setCompleted([]);
      setQuizScores([]);
    }
  };

  const pctDone = Math.round((completed.length / TOPICS.length) * 100);
  const avgScore = quizScores.length > 0
    ? Math.round(quizScores.reduce((sum, s) => sum + (s.score / s.total) * 100, 0) / quizScores.length)
    : null;

  const filteredTopics = TOPICS.filter(t => {
    if (filter === "done") return completed.includes(t.slug);
    if (filter === "pending") return !completed.includes(t.slug);
    return true;
  });

  return (
    <>
      <style>{`
        @keyframes fadeUp { from{opacity:0;transform:translateY(12px)} to{opacity:1;transform:translateY(0)} }
        @keyframes pulse { 0%,100%{transform:scale(1)} 50%{transform:scale(1.06)} }
      `}</style>
      <main style={{ maxWidth:680, margin:"0 auto", padding:"40px 20px" }}>

        {/* Header */}
        <div style={{ marginBottom:28, animation:"fadeUp 0.4s ease both" }}>
          <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:6 }}>
            <div style={{ width:40, height:40, borderRadius:12, background:"linear-gradient(135deg,#6366f1,#8b5cf6)", display:"flex", alignItems:"center", justifyContent:"center", fontSize:18, boxShadow:"0 6px 20px rgba(99,102,241,0.35)" }}>📈</div>
            <div>
              <h1 style={{ margin:0, fontSize:"1.4rem", fontWeight:800, color:"#f8fafc", letterSpacing:"-0.02em" }}>Progress Dashboard</h1>
              <p style={{ margin:0, fontSize:"0.75rem", color:"#475569" }}>Track your learning journey</p>
            </div>
          </div>
        </div>

        {/* Stat row */}
        <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:10, marginBottom:20, animation:"fadeUp 0.4s 0.05s ease both" }}>
          {[
            { val:`${completed.length}/${TOPICS.length}`, label:"Completed", sub:`${pctDone}%`, color:"#6366f1" },
            { val:quizScores.length, label:"Quizzes Taken", sub:"total", color:"#38bdf8" },
            { val: avgScore !== null ? `${avgScore}%` : "—", label:"Avg Score", sub: avgScore !== null ? (avgScore>=70?"Good":"Needs work") : "No quizzes yet", color: avgScore !== null ? scoreColor(avgScore) : "#475569" },
          ].map(s => (
            <div key={s.label} style={{ padding:"14px 16px", borderRadius:14, textAlign:"center", background:"rgba(255,255,255,0.025)", border:`1px solid ${s.color}20` }}>
              <p style={{ margin:0, fontSize:"1.4rem", fontWeight:800, color:s.color, lineHeight:1 }}>{s.val}</p>
              <p style={{ margin:"4px 0 2px", fontSize:"0.72rem", color:"#94a3b8", fontWeight:600 }}>{s.label}</p>
              <p style={{ margin:0, fontSize:"0.65rem", color:"#475569" }}>{s.sub}</p>
            </div>
          ))}
        </div>

        {/* Progress bar */}
        <div style={{ marginBottom:24, animation:"fadeUp 0.4s 0.08s ease both" }}>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:6 }}>
            <span style={{ fontSize:"0.72rem", color:"#475569", fontWeight:600, textTransform:"uppercase", letterSpacing:"0.06em" }}>Overall Completion</span>
            <span style={{ fontSize:"0.72rem", color:"#6366f1", fontWeight:700, fontFamily:"monospace" }}>{pctDone}%</span>
          </div>
          <div style={{ height:6, borderRadius:6, background:"rgba(255,255,255,0.05)", overflow:"hidden" }}>
            <div style={{ height:"100%", borderRadius:6, width:`${pctDone}%`, transition:"width 0.8s ease", background:"linear-gradient(90deg,#6366f1,#8b5cf6)" }} />
          </div>
        </div>

        {/* AI Suggestions */}
        <AISuggestions completedTopics={completed} quizScores={quizScores} allTopics={TOPICS} />

        {/* Topics section */}
        <section style={{ animation:"fadeUp 0.4s 0.2s ease both" }}>
          <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:12 }}>
            <p style={{ margin:0, fontSize:"0.72rem", color:"#475569", fontWeight:700, textTransform:"uppercase", letterSpacing:"0.07em" }}>
              Topics · <span style={{ color:"#6366f1" }}>{completed.length}</span>/{TOPICS.length} done
            </p>
            <div style={{ display:"flex", gap:4 }}>
              {["all","done","pending"].map(f => (
                <button key={f} onClick={() => setFilter(f)} style={{
                  padding:"4px 10px", borderRadius:8, border:"1px solid", fontSize:"0.68rem", fontWeight:600, cursor:"pointer", transition:"all 0.15s", textTransform:"capitalize",
                  background: filter===f ? "rgba(99,102,241,0.15)" : "transparent",
                  borderColor: filter===f ? "rgba(99,102,241,0.4)" : "rgba(255,255,255,0.07)",
                  color: filter===f ? "#a5b4fc" : "#475569",
                }}>{f}</button>
              ))}
            </div>
          </div>

          <div style={{ borderRadius:16, overflow:"hidden", border:"1px solid rgba(255,255,255,0.06)", background:"rgba(255,255,255,0.02)" }}>
            {filteredTopics.length === 0 ? (
              <div style={{ padding:"32px", textAlign:"center" }}>
                <p style={{ margin:"0 0 12px", fontSize:"0.85rem", color:"#475569" }}>
                  {filter==="done" ? "No topics completed yet." : "All topics completed! 🎉"}
                </p>
                {filter==="done" && <Link to="/" style={{ fontSize:"0.78rem", color:"#6366f1", textDecoration:"none", fontWeight:600 }}>Start Learning →</Link>}
              </div>
            ) : (
              filteredTopics.map(topic => (
                <TopicRow key={topic.slug} topic={topic}
                  isCompleted={completed.includes(topic.slug)}
                  quizData={getTopicScore(quizScores, topic.name)}
                  onToggle={handleToggle} />
              ))
            )}
          </div>
        </section>

        {/* Quiz history */}
        {quizScores.length > 0 && (
          <RecentQuizzes quizScores={quizScores} />
        )}

        {/* Footer */}
        <div style={{ marginTop:24, display:"flex", justifyContent:"space-between", alignItems:"center" }}>
          <Link to="/quiz" style={{ fontSize:"0.78rem", color:"#6366f1", textDecoration:"none", fontWeight:600 }}>🎯 Take a Quiz →</Link>
          <button onClick={handleClear} style={{ fontSize:"0.72rem", color:"#334155", background:"none", border:"none", cursor:"pointer" }}
            onMouseEnter={e => e.target.style.color="#f87171"}
            onMouseLeave={e => e.target.style.color="#334155"}>
            Clear all data
          </button>
        </div>
        <div style={{ height:40 }} />
      </main>
    </>
  );
}
